import Image from "next/image";
import PrimaryButton from "../PrimaryButton";

export default function About() {
  return (
    <div className="about">
      <div className="base">
        <h2 className="title-main">SOBRE SANTA CRISTINA XIII</h2>
        <div className="box">
          <div className="left">
            <h2>
              Viva experiências inesquecíveis na
              <span> Riviera de Santa Cristina XIII</span>
            </h2>
            <span className="span-content">
              Descubra um refúgio de tranquilidade e lazer à beira da
              deslumbrante Represa de Jurumirim. Cercado por uma natureza
              exuberante e uma infraestrutura sofisticada, o Riviera de Santa
              Cristina XIII é o destino perfeito para quem busca descanso,
              diversão e qualidade de vida.
            </span>
            <p>
              Aqui, você pode desfrutar de paisagens encantadoras, praticar
              esportes aquáticos na marina exclusiva e explorar trilhas
              ecológicas que proporcionam contato direto com a natureza. Para os
              amantes da pesca, a represa oferece um dos melhores pontos da
              região.
            </p>

            <PrimaryButton link="/contato" content="Entre em contato" variant="primary" />
          </div>
          <div className="right">
            <div className="galleryBox">
              <Image
                src="/casas/4.jpg"
                alt="asasa"
                className="galleryImage"
                width={500}
                height={500}
              />
              <Image
                src="/casas/2.jpg"
                alt="asasa"
                className="galleryImage"
                width={500}
                height={500}
              />
              <Image
                src="/casas/3.jpg"
                alt="asasa"
                className="galleryImage"
                width={500}
                height={500}
              />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
